import 'package:dartz/dartz.dart'; import 'package:injectable/injectable.dart'; import '../../entities/user_entity.dart'; import '../../repositories/i_auth_repository.dart'; @injectable class RegisterUseCase { final IAuthRepository _repo; RegisterUseCase(this._repo); Future<Either<String, UserEntity>> call({required String name, required String email, required String password}) => _repo.register(name: name, email: email, password: password); }
